import sys

def main():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    n = int(data[idx])
    m = int(data[idx+1])
    q = int(data[idx+2])
    idx += 3

    grid = [[0] * (m+2) for _ in range(n+2)]

    dp1 = [[0] * (m+2) for _ in range(n+2)]
    dp2 = [[0] * (m+2) for _ in range(n+2)]

    total = 0

    for i in range(1, n+1):
        for j in range(1, m+1):
            dp1[i][j] = 1 + dp1[i-1][j-1]
            dp2[i][j] = 1 + dp2[i-1][j+1]
            total += dp1[i][j] + dp2[i][j] - 1

    for _ in range(q):
        x = int(data[idx])
        y = int(data[idx+1])
        idx += 2

        if grid[x][y] == 0:
            grid[x][y] = 1
            for i in range(x, n+1):
                for j in range(y, m+1):
                    if i - x == j - y:
                        total -= dp1[i][j] + dp2[i][j] - 1
                        dp1[i][j] = 0
                        total += dp1[i][j] + dp2[i][j] - 1
            for i in range(x, n+1):
                for j in range(y, 0, -1):
                    if i - x == y - j:
                        total -= dp1[i][j] + dp2[i][j] - 1
                        dp2[i][j] = 0
                        total += dp1[i][j] + dp2[i][j] - 1
        else:
            grid[x][y] = 0
            for i in range(x, n+1):
                for j in range(y, m+1):
                    if i - x == j - y:
                        total -= dp1[i][j] + dp2[i][j] - 1
                        dp1[i][j] = 1 + dp1[i-1][j-1]
                        total += dp1[i][j] + dp2[i][j] - 1
            for i in range(x, n+1):
                for j in range(y, 0, -1):
                    if i - x == y - j:
                        total -= dp1[i][j] + dp2[i][j] - 1
                        dp2[i][j] = 1 + dp2[i-1][j+1]
                        total += dp1[i][j] + dp2[i][j] - 1
        print(total)

if __name__ == "__main__":
    main()

